sys_variable_value.value:
(function execute(inputs, outputs) {

    var approvers = new x_ctans_incentnow.IncentNowPortalUtils().getBusinessGroupAdmins(inputs.recbu);
    outputs.business_admin_approver="ApprovesRejectsAnyU["+approvers+"]";
    outputs.approvers_count=parseInt(approvers.split(',').length); 
    //gs.info(inputs.recbu);
})(inputs, outputs);

